#!/usr/bin/env Rscript

################################################################################
# TCGA-PRAD | Q1 vs Q4 locked-style figures
#
# Publication figures:
#   1. PCA_Minimal.pdf
#   2. Volcano_Minimal.pdf
#   3. GSEA_EMT.pdf
#
# Internal biological control:
#   4. GSEA_Hallmark_SELECTED_EXTENDED_NES_barplot_MAIN.pdf
#
# This script:
#   - Uses the canonical VST object generated by the DESeq2 module.
#   - Uses the canonical no-signature DESeq2 and GSEA results.
#   - Uses the frozen Hallmark pathway object.
#   - Does not rerun DESeq2, VST, fgsea, GSVA, ssGSEA, or msigdbr.
################################################################################

options(stringsAsFactors = FALSE, scipen = 999)

################################################################################
# 0. Frozen analytical expectations
################################################################################

EXPECTED_Q1Q4_SAMPLES <- 250L
EXPECTED_LOW_Q1 <- 125L
EXPECTED_HIGH_Q4 <- 125L

EXPECTED_VST_GENES <- 27007L
EXPECTED_SIGNATURE_ROWS <- 41L
EXPECTED_NO_SIGNATURE_GENES <- 26966L

EXPECTED_DEG_UP <- 2851L
EXPECTED_DEG_DOWN <- 707L

EXPECTED_RANKED_GENES <- 26931L
EXPECTED_HALLMARK_PATHWAYS <- 50L
EXPECTED_SIGNIFICANT_HALLMARKS <- 32L

PADJ_THRESHOLD <- 0.05
ABS_LOG2FC_THRESHOLD <- 1

EMT_PATHWAY <- "HALLMARK_EPITHELIAL_MESENCHYMAL_TRANSITION"

################################################################################
# 1. Frozen graphical constants
################################################################################

BASE_FAMILY <- "Helvetica"

TITLE_SIZE <- 6
TEXT_SIZE <- 5
FONT_SIZE <- TEXT_SIZE

LINE_SIZE <- 0.20
GRID_LW <- 0.20
BORDER_LW <- 0.20

POINT_SIZE_PCA <- 0.90
POINT_ALPHA_PCA <- 0.60
POINT_SIZE_VOLCANO <- 0.42
POINT_ALPHA_VOLCANO <- 0.60

COL_LOW <- "#044C87"
COL_HIGH <- "#EF711D"

COL_NS <- "gray80"
COL_DOWN_GENE <- "#1C5DA3"
COL_UP_GENE <- "#DB0C07"

COL_ES <- "#95B300"
COL_POS <- "#DB0C07"
COL_NEG <- "#1C5DA3"

################################################################################
# 2. Project paths
################################################################################

.repo_override <- Sys.getenv("PLATELET_REPO_ROOT", unset = "")
.script_args <- grep("^--file=", commandArgs(trailingOnly = FALSE), value = TRUE)
if (nzchar(.repo_override)) {
  .config_path <- file.path(
    normalizePath(.repo_override, winslash = "/", mustWork = TRUE),
    "bulk_tumor_validation", "tcga_prad", "Scripts", "00_config_paths.R"
  )
} else {
  if (length(.script_args) != 1L) {
    stop("Set PLATELET_REPO_ROOT when sourcing this script.", call. = FALSE)
  }
  .script_file <- normalizePath(
    sub("^--file=", "", .script_args[[1]]), winslash = "/", mustWork = TRUE
  )
  .config_path <- file.path(dirname(dirname(.script_file)), "00_config_paths.R")
}
source(.config_path, local = FALSE)
project_dir <- MODULE_DIR
rm(.repo_override, .script_args, .config_path)
if (exists(".script_file")) rm(.script_file)

script_relative_path <- file.path(
  "Scripts", "Q1Q4", "03_figures_Q1Q4_locked_style.R"
)

input_paths <- list(
  sample_metadata = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Tables", "DESeq2",
    "DESeq2_Q1Q4_sample_metadata.csv"
  ),
  full_de = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Tables", "DESeq2",
    "DESeq2_Q1Q4_41genes_full_results.csv"
  ),
  no_signature_de = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Tables", "DESeq2",
    "DESeq2_Q1Q4_41genes_no_signature_genes.csv"
  ),
  vst = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Objects",
    "DESeq2_Q1Q4_vst.rds"
  ),
  gsea_full = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Tables", "GSEA",
    "GSEA_Q1Q4_no_signature_Hallmark_full.csv"
  ),
  gsea_rank = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Objects", "GSEA",
    "GSEA_Q1Q4_DESeq2_Wald_stat_rank.rds"
  ),
  hallmark_pathways = file.path(
    GENERATED_RESULTS_DIR, "Q1Q4", "Objects", "GSEA",
    "GSEA_Q1Q4_Hallmark_pathways.rds"
  )
)

figure_root <- file.path(
  GENERATED_FIGURES_DIR, "Q1Q4"
)

pca_dir <- file.path(figure_root, "PCA")
volcano_dir <- file.path(figure_root, "Volcano")
gsea_dir <- file.path(figure_root, "GSEA")

figure_table_dir <- file.path(
  GENERATED_RESULTS_DIR, "Q1Q4", "Tables", "Figures"
)

log_dir <- file.path(
  GENERATED_RESULTS_DIR, "Q1Q4", "Logs"
)

invisible(lapply(
  c(pca_dir, volcano_dir, gsea_dir, figure_table_dir, log_dir),
  dir.create,
  recursive = TRUE,
  showWarnings = FALSE
))

output_paths <- list(
  pca = file.path(
    pca_dir,
    "PCA_Minimal.pdf"
  ),
  volcano = file.path(
    volcano_dir,
    "Volcano_Minimal.pdf"
  ),
  selected_hallmark_barplot = file.path(
    gsea_dir,
    "GSEA_Hallmark_SELECTED_EXTENDED_NES_barplot_MAIN.pdf"
  ),
  emt_gsea = file.path(
    gsea_dir,
    "GSEA_EMT.pdf"
  ),
  pca_scores = file.path(
    figure_table_dir,
    "PCA_Q1Q4_sample_scores.csv"
  ),
  pca_variance = file.path(
    figure_table_dir,
    "PCA_Q1Q4_variance_explained.csv"
  ),
  selected_hallmark_table = file.path(
    figure_table_dir,
    "GSEA_Hallmark_SELECTED_EXTENDED_internal_control.csv"
  ),
  metadata = file.path(
    figure_table_dir,
    "Figures_Q1Q4_metadata.json"
  ),
  qc = file.path(
    log_dir,
    "Figures_Q1Q4_locked_style_QC.txt"
  )
)

################################################################################
# 3. Helpers
################################################################################

msg <- function(...) {
  cat(format(Sys.time(), "%Y-%m-%d %H:%M:%S"), "|", ..., "\n")
}

fail_with_qc <- function(message_text) {
  failure_lines <- c(
    "TCGA-PRAD Q1 vs Q4 locked-style figures QC",
    "================================================",
    "",
    paste0("Date/time: ", as.character(Sys.time())),
    paste0("Project dir: ", project_dir),
    paste0("Script: ", script_relative_path),
    paste0("Failure reason: ", message_text),
    "",
    "Final status: FAIL"
  )

  writeLines(failure_lines, output_paths$qc, useBytes = TRUE)
  stop(message_text, call. = FALSE)
}

fail <- function(...) {
  fail_with_qc(paste0(...))
}

require_input <- function(path, label) {
  if (!file.exists(path)) {
    fail("Missing required input: ", label, " at ", path)
  }
}

read_required_csv <- function(path, label) {
  require_input(path, label)

  utils::read.csv(
    path,
    stringsAsFactors = FALSE,
    check.names = FALSE
  )
}

write_csv <- function(x, path) {
  utils::write.csv(
    as.data.frame(x),
    path,
    row.names = FALSE,
    quote = TRUE
  )
}

parse_logical_strict <- function(x, label) {
  if (is.logical(x)) {
    return(x)
  }

  value <- tolower(trimws(as.character(x)))
  output <- rep(NA, length(value))

  output[value %in% c("true", "t", "1")] <- TRUE
  output[value %in% c("false", "f", "0")] <- FALSE

  invalid <- is.na(output) & !is.na(value) & value != ""

  if (any(invalid)) {
    fail(
      "Column '", label,
      "' contains invalid logical values: ",
      paste(unique(value[invalid]), collapse = ", ")
    )
  }

  output
}

clean_hallmark_label <- function(pathway) {
  pathway_clean <- gsub("^HALLMARK_", "", pathway)
  pathway_clean <- gsub("_", " ", pathway_clean)
  pathway_clean <- tools::toTitleCase(tolower(pathway_clean))

  pathway_clean <- gsub("Tnfa", "TNF-alpha", pathway_clean)
  pathway_clean <- gsub("Nfkb", "NFkB", pathway_clean)
  pathway_clean <- gsub("Il6 Jak Stat3", "IL-6/JAK/STAT3", pathway_clean)
  pathway_clean <- gsub("Il2 Stat5", "IL2/STAT5", pathway_clean)
  pathway_clean <- gsub("Kras", "KRAS", pathway_clean)
  pathway_clean <- gsub("Tgf Beta", "TGF-beta", pathway_clean)
  pathway_clean <- gsub("P53", "p53", pathway_clean)
  pathway_clean <- gsub("Myc", "MYC", pathway_clean)
  pathway_clean <- gsub("Signaling", "signaling", pathway_clean)
  pathway_clean <- gsub("Via", "via", pathway_clean)

  pathway_clean
}

format_scientific <- function(x, digits = 2) {
  if (is.na(x)) {
    return(NA_character_)
  }

  format(
    x,
    scientific = TRUE,
    digits = digits,
    trim = TRUE
  )
}

validate_pdf <- function(path, label) {
  if (!file.exists(path)) {
    fail(label, " was not generated: ", path)
  }

  file_size <- file.info(path)$size

  if (is.na(file_size) || file_size <= 0) {
    fail(label, " is empty or invalid: ", path)
  }
}

################################################################################
# 4. Required packages
################################################################################

required_packages <- c(
  "SummarizedExperiment",
  "ggplot2",
  "patchwork",
  "jsonlite"
)

missing_packages <- required_packages[
  !vapply(
    required_packages,
    requireNamespace,
    logical(1),
    quietly = TRUE
  )
]

if (length(missing_packages) > 0) {
  stop(
    paste0(
      "Missing required package(s): ",
      paste(missing_packages, collapse = ", "),
      ". The script does not install packages."
    ),
    call. = FALSE
  )
}

################################################################################
# 5. Validate required inputs
################################################################################

msg("Project dir:", project_dir)

for (nm in names(input_paths)) {
  require_input(input_paths[[nm]], nm)
}

################################################################################
# 6. Load and validate the canonical Q1/Q4 sample metadata
################################################################################

msg("[1/9] Loading canonical Q1/Q4 sample metadata")

sample_metadata <- read_required_csv(
  input_paths$sample_metadata,
  "Q1/Q4 sample metadata"
)

required_metadata_columns <- c(
  "sample_id",
  "patient_id",
  "platelet_score_group",
  "Score_raw",
  "Score_z"
)

missing_metadata_columns <- setdiff(
  required_metadata_columns,
  names(sample_metadata)
)

if (length(missing_metadata_columns) > 0) {
  fail(
    "Sample metadata is missing required columns: ",
    paste(missing_metadata_columns, collapse = ", ")
  )
}

sample_metadata$sample_id <- trimws(
  as.character(sample_metadata$sample_id)
)

sample_metadata$patient_id <- trimws(
  as.character(sample_metadata$patient_id)
)

sample_metadata$platelet_score_group <- trimws(
  as.character(sample_metadata$platelet_score_group)
)

sample_metadata$Score_raw <- suppressWarnings(
  as.numeric(sample_metadata$Score_raw)
)

sample_metadata$Score_z <- suppressWarnings(
  as.numeric(sample_metadata$Score_z)
)

if (nrow(sample_metadata) != EXPECTED_Q1Q4_SAMPLES) {
  fail(
    "Expected ", EXPECTED_Q1Q4_SAMPLES,
    " Q1/Q4 samples. Observed: ",
    nrow(sample_metadata)
  )
}

if (anyDuplicated(sample_metadata$sample_id)) {
  fail("Sample metadata contains duplicated sample IDs.")
}

if (anyDuplicated(sample_metadata$patient_id)) {
  fail("Sample metadata contains duplicated patient IDs.")
}

if (
  any(!is.finite(sample_metadata$Score_raw)) ||
  any(!is.finite(sample_metadata$Score_z))
) {
  fail("Sample metadata contains non-finite score values.")
}

group_counts <- table(
  factor(
    sample_metadata$platelet_score_group,
    levels = c("LOW_Q1", "HIGH_Q4")
  )
)

if (
  as.integer(group_counts["LOW_Q1"]) != EXPECTED_LOW_Q1 ||
  as.integer(group_counts["HIGH_Q4"]) != EXPECTED_HIGH_Q4
) {
  fail(
    "Unexpected Q1/Q4 group counts. Observed: ",
    paste(
      names(group_counts),
      as.integer(group_counts),
      sep = "=",
      collapse = "; "
    )
  )
}

sample_metadata$Group <- ifelse(
  sample_metadata$platelet_score_group == "LOW_Q1",
  "Platelet Score Low",
  "Platelet Score High"
)

sample_metadata$Group <- factor(
  sample_metadata$Group,
  levels = c(
    "Platelet Score Low",
    "Platelet Score High"
  )
)

################################################################################
# 7. Load the canonical VST and define the PCA gene universe
################################################################################

msg("[2/9] Loading canonical VST object")

vst_object <- readRDS(input_paths$vst)

if (!inherits(vst_object, "SummarizedExperiment")) {
  fail(
    "VST object must inherit from SummarizedExperiment. Class: ",
    paste(class(vst_object), collapse = ", ")
  )
}

vst_matrix <- SummarizedExperiment::assay(vst_object)

if (is.null(dim(vst_matrix)) || length(dim(vst_matrix)) != 2) {
  fail("VST assay is not a two-dimensional matrix-like object.")
}

if (nrow(vst_matrix) != EXPECTED_VST_GENES) {
  fail(
    "Expected ", EXPECTED_VST_GENES,
    " genes in the VST object. Observed: ",
    nrow(vst_matrix)
  )
}

if (ncol(vst_matrix) != EXPECTED_Q1Q4_SAMPLES) {
  fail(
    "Expected ", EXPECTED_Q1Q4_SAMPLES,
    " samples in the VST object. Observed: ",
    ncol(vst_matrix)
  )
}

if (
  any(!is.finite(vst_matrix)) ||
  anyDuplicated(rownames(vst_matrix)) ||
  anyDuplicated(colnames(vst_matrix))
) {
  fail(
    "VST matrix contains non-finite values or duplicated row/column names."
  )
}

if (!setequal(colnames(vst_matrix), sample_metadata$sample_id)) {
  fail("VST and sample metadata contain different sample sets.")
}

sample_metadata <- sample_metadata[
  match(colnames(vst_matrix), sample_metadata$sample_id),
  ,
  drop = FALSE
]

if (!identical(sample_metadata$sample_id, colnames(vst_matrix))) {
  fail("VST and sample metadata could not be aligned.")
}

full_de <- read_required_csv(
  input_paths$full_de,
  "full DESeq2 result table"
)

required_full_de_columns <- c(
  "ensembl_id",
  "is_signature_gene"
)

missing_full_de_columns <- setdiff(
  required_full_de_columns,
  names(full_de)
)

if (length(missing_full_de_columns) > 0) {
  fail(
    "Full DESeq2 table is missing required columns: ",
    paste(missing_full_de_columns, collapse = ", ")
  )
}

full_de$ensembl_id <- trimws(as.character(full_de$ensembl_id))

full_de$is_signature_gene <- parse_logical_strict(
  full_de$is_signature_gene,
  "is_signature_gene"
)

if (nrow(full_de) != EXPECTED_VST_GENES) {
  fail(
    "Expected ", EXPECTED_VST_GENES,
    " rows in the full DESeq2 table. Observed: ",
    nrow(full_de)
  )
}

if (anyDuplicated(full_de$ensembl_id)) {
  fail("Full DESeq2 table contains duplicated Ensembl IDs.")
}

if (!setequal(rownames(vst_matrix), full_de$ensembl_id)) {
  fail("VST and full DESeq2 table contain different gene sets.")
}

full_de_order <- match(
  rownames(vst_matrix),
  full_de$ensembl_id
)

signature_mask <- full_de$is_signature_gene[full_de_order]

if (any(is.na(signature_mask))) {
  fail("Signature annotation could not be aligned to all VST rows.")
}

n_signature_rows <- sum(signature_mask)
n_no_signature_rows <- sum(!signature_mask)

if (n_signature_rows != EXPECTED_SIGNATURE_ROWS) {
  fail(
    "Expected ", EXPECTED_SIGNATURE_ROWS,
    " signature rows in the VST object. Observed: ",
    n_signature_rows
  )
}

if (n_no_signature_rows != EXPECTED_NO_SIGNATURE_GENES) {
  fail(
    "Expected ", EXPECTED_NO_SIGNATURE_GENES,
    " no-signature VST genes. Observed: ",
    n_no_signature_rows
  )
}

vst_pca <- vst_matrix[
  !signature_mask,
  ,
  drop = FALSE
]

################################################################################
# 8. PCA
################################################################################

msg("[3/9] Generating locked-style PCA")

pca_object <- stats::prcomp(
  t(vst_pca),
  center = TRUE,
  scale. = FALSE
)

variance_explained <- (
  pca_object$sdev^2 /
    sum(pca_object$sdev^2)
) * 100

pca_scores <- data.frame(
  sample_id = rownames(pca_object$x),
  PC1 = as.numeric(pca_object$x[, 1]),
  PC2 = as.numeric(pca_object$x[, 2]),
  stringsAsFactors = FALSE
)

metadata_order <- match(
  pca_scores$sample_id,
  sample_metadata$sample_id
)

pca_scores$patient_id <- sample_metadata$patient_id[metadata_order]

pca_scores$platelet_score_group <-
  sample_metadata$platelet_score_group[metadata_order]

pca_scores$Group <- sample_metadata$Group[metadata_order]
pca_scores$Score_raw <- sample_metadata$Score_raw[metadata_order]
pca_scores$Score_z <- sample_metadata$Score_z[metadata_order]

if (any(is.na(pca_scores$Group))) {
  fail("PCA scores could not be aligned to sample groups.")
}

variance_table <- data.frame(
  principal_component = paste0(
    "PC",
    seq_along(variance_explained)
  ),
  variance_explained_percent = as.numeric(
    variance_explained
  ),
  cumulative_variance_percent = cumsum(
    variance_explained
  ),
  stringsAsFactors = FALSE
)

write_csv(pca_scores, output_paths$pca_scores)
write_csv(variance_table, output_paths$pca_variance)

x_range <- range(pca_scores$PC1, na.rm = TRUE)
y_range <- range(pca_scores$PC2, na.rm = TRUE)

x_span <- diff(x_range)
y_span <- diff(y_range)

if (
  !is.finite(x_span) ||
  x_span == 0 ||
  !is.finite(y_span) ||
  y_span == 0
) {
  fail("PCA plotting range is zero or non-finite.")
}

x_label <- max(pca_scores$PC1, na.rm = TRUE) - 0.005 * x_span
y_label_low <- min(pca_scores$PC2, na.rm = TRUE) - 0.11 * y_span
y_label_high <- min(pca_scores$PC2, na.rm = TRUE) - 0.20 * y_span

pca_plot <- ggplot2::ggplot(
  pca_scores,
  ggplot2::aes(
    x = PC1,
    y = PC2,
    color = Group
  )
) +
  ggplot2::geom_point(
    size = POINT_SIZE_PCA,
    alpha = POINT_ALPHA_PCA,
    shape = 16
  ) +
  ggplot2::scale_color_manual(
    values = c(
      "Platelet Score Low" = COL_LOW,
      "Platelet Score High" = COL_HIGH
    ),
    name = NULL
  ) +
  ggplot2::annotate(
    "text",
    x = x_label,
    y = y_label_low,
    label = "Platelet score low",
    hjust = 1,
    vjust = 0.5,
    color = COL_LOW,
    family = BASE_FAMILY,
    fontface = "plain",
    size = 4.5 / ggplot2::.pt
  ) +
  ggplot2::annotate(
    "text",
    x = x_label,
    y = y_label_high,
    label = "Platelet score high",
    hjust = 1,
    vjust = 0.5,
    color = COL_HIGH,
    family = BASE_FAMILY,
    fontface = "plain",
    size = 4.5 / ggplot2::.pt
  ) +
  ggplot2::labs(
    x = paste0(
      "PC1 (",
      round(variance_explained[1], 2),
      "%)"
    ),
    y = paste0(
      "PC2 (",
      round(variance_explained[2], 2),
      "%)"
    )
  ) +
  ggplot2::theme_bw(
    base_size = TEXT_SIZE,
    base_family = BASE_FAMILY
  ) +
  ggplot2::theme(
    text = ggplot2::element_text(
      family = BASE_FAMILY,
      size = TEXT_SIZE,
      color = "black"
    ),
    legend.position = "none",
    axis.title = ggplot2::element_text(
      size = 4.5,
      color = "black"
    ),
    axis.text = ggplot2::element_text(
      size = 4.3,
      color = "black"
    ),
    axis.ticks = ggplot2::element_line(
      linewidth = 0.20,
      color = "black"
    ),
    panel.grid.major = ggplot2::element_line(
      linewidth = 0.14,
      color = "grey95"
    ),
    panel.grid.minor = ggplot2::element_blank(),
    panel.border = ggplot2::element_rect(
      linewidth = 0.20,
      colour = "black",
      fill = NA
    ),
    plot.margin = grid::unit(
      c(2, 2, 2, 2),
      "mm"
    )
  )

ggplot2::ggsave(
  filename = output_paths$pca,
  plot = pca_plot,
  width = 4.2,
  height = 3.8,
  units = "cm",
  device = "pdf"
)

validate_pdf(output_paths$pca, "PCA figure")

################################################################################
# 9. Volcano
################################################################################

msg("[4/9] Generating locked-style volcano plot")

no_signature_de <- read_required_csv(
  input_paths$no_signature_de,
  "no-signature DESeq2 result table"
)

required_no_signature_columns <- c(
  "ensembl_id",
  "gene_name",
  "log2FoldChange",
  "log2FoldChange_shrunken",
  "padj",
  "is_signature_gene"
)

missing_no_signature_columns <- setdiff(
  required_no_signature_columns,
  names(no_signature_de)
)

if (length(missing_no_signature_columns) > 0) {
  fail(
    "No-signature DESeq2 table is missing required columns: ",
    paste(missing_no_signature_columns, collapse = ", ")
  )
}

if (nrow(no_signature_de) != EXPECTED_NO_SIGNATURE_GENES) {
  fail(
    "Expected ", EXPECTED_NO_SIGNATURE_GENES,
    " no-signature DESeq2 rows. Observed: ",
    nrow(no_signature_de)
  )
}

no_signature_de$is_signature_gene <- parse_logical_strict(
  no_signature_de$is_signature_gene,
  "is_signature_gene"
)

if (any(no_signature_de$is_signature_gene %in% TRUE, na.rm = TRUE)) {
  fail("No-signature DESeq2 input still contains signature genes.")
}

no_signature_de$log2FoldChange <- suppressWarnings(
  as.numeric(no_signature_de$log2FoldChange)
)

no_signature_de$log2FoldChange_shrunken <- suppressWarnings(
  as.numeric(no_signature_de$log2FoldChange_shrunken)
)

no_signature_de$padj <- suppressWarnings(
  as.numeric(no_signature_de$padj)
)

plot_log2fc <- no_signature_de$log2FoldChange_shrunken

fallback_rows <- !is.finite(plot_log2fc) &
  is.finite(no_signature_de$log2FoldChange)

plot_log2fc[fallback_rows] <-
  no_signature_de$log2FoldChange[fallback_rows]

if (any(!is.finite(plot_log2fc))) {
  fail(
    "Volcano effect-size column contains non-finite values after fallback."
  )
}

negative_log10_fdr <- -log10(
  pmax(no_signature_de$padj, 1e-300)
)

significance <- ifelse(
  !is.na(no_signature_de$padj) &
    no_signature_de$padj < PADJ_THRESHOLD &
    plot_log2fc > ABS_LOG2FC_THRESHOLD,
  "Upregulated",
  ifelse(
    !is.na(no_signature_de$padj) &
      no_signature_de$padj < PADJ_THRESHOLD &
      plot_log2fc < -ABS_LOG2FC_THRESHOLD,
    "Downregulated",
    "Not significant"
  )
)

