# 12. EMT GSEA running-score plot
################################################################################

msg("[7/9] Generating locked-style EMT GSEA curve")

ranks <- readRDS(input_paths$gsea_rank)

if (
  !is.numeric(ranks) ||
  is.null(names(ranks)) ||
  any(names(ranks) == "") ||
  any(!is.finite(ranks))
) {
  fail("Canonical GSEA rank object is invalid.")
}

if (length(ranks) != EXPECTED_RANKED_GENES) {
  fail(
    "Expected ", EXPECTED_RANKED_GENES,
    " ranked genes. Observed: ",
    length(ranks)
  )
}

if (anyDuplicated(names(ranks))) {
  fail("Canonical GSEA rank object contains duplicated gene names.")
}

ranks <- sort(ranks, decreasing = TRUE)

hallmark_pathways <- readRDS(
  input_paths$hallmark_pathways
)

if (!is.list(hallmark_pathways)) {
  fail("Frozen Hallmark pathway object is not a list.")
}

if (length(hallmark_pathways) != EXPECTED_HALLMARK_PATHWAYS) {
  fail(
    "Expected ", EXPECTED_HALLMARK_PATHWAYS,
    " pathways in the frozen Hallmark object. Observed: ",
    length(hallmark_pathways)
  )
}

if (!EMT_PATHWAY %in% names(hallmark_pathways)) {
  fail(
    "Frozen Hallmark pathway object does not contain ",
    EMT_PATHWAY,
    "."
  )
}

emt_genes <- unique(
  as.character(
    hallmark_pathways[[EMT_PATHWAY]]
  )
)

emt_genes_in_rank <- intersect(
  emt_genes,
  names(ranks)
)

number_ranked_genes <- length(ranks)
number_emt_genes <- length(emt_genes_in_rank)

if (number_emt_genes < 10) {
  fail(
    "Too few EMT genes were found in the canonical rank: ",
    number_emt_genes
  )
}

hit_positions <- which(
  names(ranks) %in% emt_genes_in_rank
)

hit_indicator <- logical(number_ranked_genes)
hit_indicator[hit_positions] <- TRUE

hit_weights <- abs(ranks[hit_positions])
hit_weights <- hit_weights / sum(hit_weights)

miss_penalty <- 1 / (
  number_ranked_genes - number_emt_genes
)

running_score <- numeric(number_ranked_genes)

current_score <- 0
hit_index <- 1L

for (i in seq_len(number_ranked_genes)) {
  if (hit_indicator[i]) {
    current_score <- current_score + hit_weights[hit_index]
    hit_index <- hit_index + 1L
  } else {
    current_score <- current_score - miss_penalty
  }

  running_score[i] <- current_score
}

positive_es <- max(running_score, na.rm = TRUE)
negative_es <- min(running_score, na.rm = TRUE)

manual_es <- if (
  abs(positive_es) >= abs(negative_es)
) {
  positive_es
} else {
  negative_es
}

emt_result <- gsea_full[
  gsea_full$pathway == EMT_PATHWAY,
  ,
  drop = FALSE
]

if (nrow(emt_result) != 1L) {
  fail(
    "Expected exactly one EMT result in the GSEA table. Observed: ",
    nrow(emt_result)
  )
}

emt_nes <- emt_result$NES
emt_fdr <- emt_result$padj
emt_fgsea_es <- emt_result$ES

manual_es_difference <- abs(
  manual_es - emt_fgsea_es
)

if (!is.finite(manual_es_difference)) {
  fail("Manual and canonical EMT ES values could not be compared.")
}

if (manual_es_difference > 1e-6) {
  fail(
    "Manual EMT running-score reconstruction does not match the canonical ",
    "fgsea ES. Difference: ",
    format(manual_es_difference, scientific = TRUE)
  )
}

metrics_block <- paste(
  c(
    paste0(
      "NES = ",
      round(emt_nes, 2)
    ),
    paste0(
      "FDR = ",
      format_scientific(emt_fdr, digits = 2)
    )
  ),
  collapse = "\n"
)

df_es <- data.frame(
  rank = seq_len(number_ranked_genes),
  ES = running_score
)

df_hits <- data.frame(
  rank = hit_positions
)

df_metric <- data.frame(
  rank = seq_len(number_ranked_genes),
  metric = as.numeric(ranks)
)

lower_quantile <- as.numeric(
  stats::quantile(
    df_metric$metric,
    0.01,
    na.rm = TRUE
  )
)

upper_quantile <- as.numeric(
  stats::quantile(
    df_metric$metric,
    0.99,
    na.rm = TRUE
  )
)

df_metric$metric_clip <- pmax(
  lower_quantile,
  pmin(
    upper_quantile,
    df_metric$metric
  )
)

df_strip <- data.frame(
  rank = df_metric$rank,
  y = 0,
  z = df_metric$metric_clip
)

